import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    import numpy as np

    def distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def calculate_time_to_customer(truck_pos, customer_pos, speed):
        return distance(truck_pos, customer_pos) / speed

    def calculate_total_time(truck_pos, customer_pos, speed, time_windows, current_time):
        time_to_customer = calculate_time_to_customer(truck_pos, customer_pos, speed)
        waiting_time = max(0, time_windows[1] - (current_time + time_to_customer))
        return time_to_customer + waiting_time

    best_node = None
    min_total_time = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        time_to_customer = calculate_total_time(cur_truck_pos, customer_pos, truck_speed, time_windows[idx], current_time)
        if time_to_customer < min_total_time:
            min_total_time = time_to_customer
            best_node = idx

    return best_node
